// ─────────────────────────────────────────────────────────────
// MERGE AND CLEAN
// ─────────────────────────────────────────────────────────────

function normalize(name) {
  return name
    .toLowerCase()
    .replace(/[.,\-'"()]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function truncate(name, max = 100) {
  if (!name || name.length <= max) return name;
  const cut = name.lastIndexOf(' ', max - 1);
  return cut > 0 ? name.substring(0, cut) : name.substring(0, max);
}

// Read existing
const existing = JSON.parse(fs.readFileSync(OUTPUT_FILE, 'utf8'));

// Normalize category names in existing data (merge old Agriculture/Alimentation)
const categoryMap = {
  'Agriculture': 'Agriculture et Alimentation',
  'Alimentation et Boissons': 'Agriculture et Alimentation',
  'Alimentation': 'Agriculture et Alimentation',
};

const cleanedExisting = existing.map(c => ({
  ...c,
  entreprise: truncate(c.entreprise || ''),
  category: categoryMap[c.category] || c.category,
}));

// Build new companies arrays with category field
const newCompanies = [
  ...transportCompanies.map(c => ({ ...c, category: 'Transport et Logistique' })),
  ...btpCompanies.map(c => ({ ...c, category: 'Construction et BTP' })),
  ...immobilierCompanies.map(c => ({ ...c, category: 'Immobilier' })),
  ...santeCompanies.map(c => ({ ...c, category: 'Santé et Pharmacie' })),
  ...restaurationCompanies.map(c => ({ ...c, category: 'Restauration et Hôtellerie' })),
  ...agricultureCompanies.map(c => ({ ...c, category: 'Agriculture et Alimentation' })),
  ...informatiqueCompanies.map(c => ({ ...c, category: 'Informatique et Numérique' })),
].map(c => ({ ...c, entreprise: truncate(c.entreprise || '') }));

// Deduplicate: start with existing, add new ones not already present
const seen = new Set(cleanedExisting.map(c => normalize(c.entreprise)));
const toAdd = [];

for (const c of newCompanies) {
  const key = normalize(c.entreprise);
  if (!seen.has(key)) {
    seen.add(key);
    toAdd.push(c);
  }
}

const merged = [...cleanedExisting, ...toAdd];

fs.writeFileSync(OUTPUT_FILE, JSON.stringify(merged, null, 2), 'utf8');

console.log('\n=== REBUILD COMPLETE ===');
console.log(`Total companies: ${merged.length}`);
console.log(`  Existing (normalized): ${cleanedExisting.length}`);
console.log(`  New added: ${toAdd.length}`);
console.log('\nBy category:');

const byCategory = {};
for (const c of merged) {
  byCategory[c.category] = (byCategory[c.category] || 0) + 1;
}
Object.entries(byCategory)
  .sort((a, b) => b[1] - a[1])
  .forEach(([cat, count]) => {
    console.log(`  ${cat}: ${count}`);
  });
